var documenterSearchIndex = {"docs":
[{"category":"section","location":"examples/03_basic_lotka_volterra/","page":"Basic Lotka-Volterra","text":"ENV[\"GKSwstype\"] = \"100\";\nnothing #hide","title":"Basic Lotka-Volterra"},{"category":"section","location":"examples/03_basic_lotka_volterra/#Basic-Lotka-Volterra-System","page":"Basic Lotka-Volterra","text":"This example introduces a more robust way to initialize the MDC direction. Instead of making a lucky guess, we compute the local Hessian of the cost function at the nominal parameters. The eigenvector corresponding to the smallest eigenvalue gives us the direction of least resistance (the most unidentifiable direction).\n\nWe also move away from matching raw trajectories and instead match structural features of the system: the mean prey population and the maximum predator population.\n\nusing LinearAlgebra, OrdinaryDiffEq, MinimallyDisruptiveCurves, Statistics, Plots, ForwardDiff, LaTeXStrings\n\nWhich eigenvector (direction) to explore along the manifold. They tend to be iteratively more disruptive.\n\nwhich_dir = 1","title":"Basic Lotka-Volterra System"},{"category":"section","location":"examples/03_basic_lotka_volterra/#Simulator-(Lotka-Volterra)","page":"Basic Lotka-Volterra","text":"function lotka_volterra_dynamics!(du, u, p, t)\n    du[1] = p[1] * u[1] - p[2] * u[1] * u[2]\n    du[2] = -p[3] * u[2] + p[4] * u[1] * u[2]\n    return nothing\nend\n\nu0 = [1.0, 1.0]\ntspan = (0.0, 10.0)\np_nominal = [1.5, 1.0, 3.0, 1.0]\n\nnom_prob = ODEProblem(lotka_volterra_dynamics!, u0, tspan, p_nominal)\n\n#Helper for evaluations\nsolve_at_p(p) = solve(remake(nom_prob; p = p), Tsit5())","title":"Simulator (Lotka-Volterra)"},{"category":"section","location":"examples/03_basic_lotka_volterra/#Objective-Features-and-Cost-Framework","page":"Basic Lotka-Volterra","text":"Here we extract features from the simulation: the mean of the prey and the max of the predator.\n\nfunction extract_features(p)\n    sol = solve_at_p(p)\n    grid = range(0.0, 10.0, length = 200)\n    mean_prey = mean(sol(t)[1] for t in grid)\n    max_predator = maximum(sol(t)[2] for t in grid)\n    return [mean_prey, max_predator]\nend\n\nnom_features = extract_features(p_nominal)\n\nfunction loss(p)\n    p_features = extract_features(p)\n    return sum(abs2, p_features .- nom_features)\nend\n\nfunction loss_grad!(g, p)\n    ForwardDiff.gradient!(g, loss, p)\n    return g\nend\n\ncore_cost = CostFunction(loss, loss_grad!)","title":"Objective Features & Cost Framework"},{"category":"section","location":"examples/03_basic_lotka_volterra/#Execution-Pipeline","page":"Basic Lotka-Volterra","text":"Compute the local Hessian at nominal parameters to discover insensitive directions.\n\nprintln(\"--- Setting up Lotka-Volterra MDC System ---\")\n\nhess0 = ForwardDiff.hessian(loss, p_nominal)\neigen_decomposition = eigen(hess0)\ninit_dir = eigen_decomposition.vectors[:, which_dir]\n\nsys = MDCProblem(\n    core_cost,\n    p_nominal,\n    init_dir,\n    1.0;\n    names = [:p₁, :p₂, :p₃, :p₄]\n)\n\nprintln(\"Launching MDC integration...\")\nmdc_curves = MDCSolve(sys, span = MDCSpan(-3.0, 8.0))","title":"Execution Pipeline"},{"category":"section","location":"examples/03_basic_lotka_volterra/#Animation-Pipeline-Integration","page":"Basic Lotka-Volterra","text":"println(\"\\nPreparing MDC animation...\")\n\n#Define the live sandbox rendering function\nfunction lotka_volterra_sandbox_painter(θ_physical)\n    plot_t_grid = range(tspan[1], tspan[2], length = 200)\n\n    sol_nominal = solve_at_p(p_nominal)\n    sol_perturbed = solve_at_p(θ_physical)\n\n    states_nom = [sol_nominal(t_val) for t_val in plot_t_grid]\n    states_pert = [sol_perturbed(t_val) for t_val in plot_t_grid]\n\n    prey_nominal = [u[1] for u in states_nom]\n    pred_nominal = [u[2] for u in states_nom]\n\n    prey_perturbed = [u[1] for u in states_pert]\n    pred_perturbed = [u[2] for u in states_pert]\n\n    mean_prey_nom = mean(prey_nominal)\n    mean_prey_pert = mean(prey_perturbed)\n    max_pred_nom = maximum(pred_nominal)\n    max_pred_pert = maximum(pred_perturbed)\n\n    Plots.plot!(\n        plot_t_grid, [prey_nominal pred_nominal],\n        subplot = 1,\n        linealpha = 0.2, linestyle = :dash,\n        color = [:blue :red], label = false\n    )\n\n    Plots.plot!(\n        plot_t_grid, [prey_perturbed pred_perturbed],\n        subplot = 1,\n        linewidth = 2,\n        color = [:blue :red], label = [\"Prey (x)\" \"Predator (y)\"],\n        legend = :topright\n    )\n\n    Plots.hline!([mean_prey_nom], subplot = 1, linestyle = :dot, linealpha = 0.4, color = :blue, label = false)\n    Plots.hline!([max_pred_nom], subplot = 1, linestyle = :dot, linealpha = 0.4, color = :red, label = false)\n\n    Plots.hline!([mean_prey_pert], subplot = 1, linestyle = :dashdot, linewidth = 1.2, color = :darkblue, label = \"Mean Prey\")\n    Plots.hline!([max_pred_pert], subplot = 1, linestyle = :dashdot, linewidth = 1.2, color = :darkred, label = \"Max Predator\")\n\n    return Plots.plot!(\n        subplot = 1,\n        xlabel = \"Time\", ylabel = \"Population\",\n        xlims = tspan,\n        ylims = (0.0, 6.0)\n    )\nend\n\n#Invoke the updated linear animation tracking utility function\nlv_animation = MinimallyDisruptiveCurves.animate_mdc(\n    mdc_curves,\n    lotka_volterra_sandbox_painter;\n    fps = 20,\n    density = 150,\n    raw = true\n)\n\noutput_path = joinpath(pwd(), \"lotka_volterra_mdc.gif\")\nprintln(\"Rendering frames and saving video to: $output_path\")\nPlots.gif(lv_animation, output_path);\nnothing #hide\n\n(Image: Lotka Volterra MDC Sweep)\n\n\n\nThis page was generated using Literate.jl.","title":"Animation Pipeline Integration"},{"category":"section","location":"examples/04_lotka_volterra_with_optim/","page":"MTK Lotka-Volterra","text":"ENV[\"GKSwstype\"] = \"100\"","title":"MTK Lotka-Volterra"},{"category":"section","location":"examples/04_lotka_volterra_with_optim/#MTK-Lotka-Volterra-with-Optimized-Gradients","page":"MTK Lotka-Volterra","text":"This example does the same Lotka-Volterra model, but builds it with ModelingToolkit (MTK). MTK allows us to symbolically define our equations and automatically generate efficient, type-stable code.\n\nTo ensure our gradients remain allocation-free and fully compatible with ForwardDiff dual numbers, we introduce PreallocationTools and DiffCache. This is the recommended pattern for performance-critical, simulation-based costs.\n\nusing ModelingToolkit, Plots\nusing OrdinaryDiffEq\nusing ForwardDiff\nusing PreallocationTools\nusing SymbolicIndexingInterface\nusing SymbolicIndexingInterface: parameter_values\nusing SciMLStructures: Tunable, canonicalize, replace\nusing SciMLBase, LinearAlgebra\nimport ModelingToolkit.t_nounits\nimport ModelingToolkit.D_nounits\nimport ModelingToolkit: SymbolicT\nusing Printf\nusing Statistics\nusing MinimallyDisruptiveCurves\n\nGlobal Configuration Parameters\n\nconst TSPAN_PHYSICAL = (0.0, 10.0)  #Time horizon for the differential equations\nconst EXPLORATION_DIR = 2           #Hessian eigenvector index selected for curve evolution","title":"MTK Lotka-Volterra with Optimized Gradients"},{"category":"section","location":"examples/04_lotka_volterra_with_optim/#Model-Definition-via-ModelingToolkit-(MTK)","page":"MTK Lotka-Volterra","text":"@component function LotkaVolterra(;\n        name, α = 1.5, β = 1.0, γ = 1.0, δ = 3.0\n    )\n    @parameters begin\n        α = α\n        β = β\n        γ = γ\n        δ = δ\n    end\n    params = SymbolicT[]\n    push!(params, α); push!(params, β); push!(params, γ); push!(params, δ)\n\n    @variables begin\n        x(t_nounits) = 1.0\n        y(t_nounits) = 1.0\n    end\n    vars = SymbolicT[]\n    push!(vars, x); push!(vars, y)\n\n    eqs = Equation[]\n    push!(eqs, D_nounits(x) ~ α * x - β * x * y)\n    push!(eqs, D_nounits(y) ~ -δ * y + γ * x * y)\n\n    return System(\n        eqs, t_nounits, vars, params;\n        systems = System[], name\n    )\nend\n\n@named lv = LotkaVolterra()\nsys = complete(lv)\nprob = ODEProblem(sys, [], TSPAN_PHYSICAL)\nparams_to_optimize = tunable_parameters(sys) ∩ parameters(sys)\n\n#Define tracking observables (State arrays)\ntarget_observables = [sys.x, sys.y]","title":"Model Definition via ModelingToolkit (MTK)"},{"category":"section","location":"examples/04_lotka_volterra_with_optim/#Generate-Baseline-Experimental-Features-(\"Truth\")","page":"MTK Lotka-Volterra","text":"grid_steps = range(TSPAN_PHYSICAL[1], TSPAN_PHYSICAL[2], length = 200)\nsol_nominal = solve(prob, Tsit5(); saveat = grid_steps)\ntspan = TSPAN_PHYSICAL\n\nnom_data = sol_nominal(grid_steps, idxs = target_observables)\nconst nom_features = [\n    mean(nom_data[1, :]),    #Mean Prey (x)\n    maximum(nom_data[2, :]),  #Max Predator (y)\n]\nsolve_at_p(p) = solve(remake(prob; p = p), Tsit5())","title":"Generate Baseline Experimental Features (\"Truth\")"},{"category":"section","location":"examples/04_lotka_volterra_with_optim/#High-Performance-Loss-Function","page":"MTK Lotka-Volterra","text":"We use DiffCache to create a buffer that can safely hold dual numbers. The replace function updates the parameter container without breaking MTK's structural typing.\n\nfunction loss_function(p_active, p_tuple)\n    #Destructure context tuple\n    odeprob, ts, features_target, setter, diffcache, obs_symbols = p_tuple\n\n    ps = parameter_values(odeprob)\n    buffer = get_tmp(diffcache, p_active)\n\n    #Block-copy baseline values safely\n    copyto!(buffer, canonicalize(Tunable(), ps)[1])\n\n    #Type-safe structural parameter container replacement for ForwardDiff\n    ps_updated = replace(Tunable(), ps, buffer)\n\n    #Mutate only our active dual/float optimization array\n    setter(ps_updated, p_active)\n\n    #Fast inferred problem recreation\n    newprob = remake(odeprob; p = ps_updated)\n    sol = solve(newprob, Tsit5(); saveat = ts)\n\n    if sol.retcode != SciMLBase.ReturnCode.Success\n        return eltype(p_active)(1.0e6) #Prevents NaN in Hessian\n    end\n\n    #Track states dynamically without allocations\n    current_data = sol(ts, idxs = obs_symbols)\n\n    #Extract structural feature criteria allocation-free\n    mean_prey = mean(@view current_data[1, :])\n    max_predator = maximum(@view current_data[2, :])\n\n    return sum(abs2, [mean_prey, max_predator] .- features_target)\nend","title":"High-Performance Loss Function"},{"category":"section","location":"examples/04_lotka_volterra_with_optim/#Build-the-MDC-context","page":"MTK Lotka-Volterra","text":"setter = setp(prob, params_to_optimize)\ngetter = getp(prob, params_to_optimize)\n\nraw_ps = parameter_values(prob)\ntunable_vector_prototype = copy(canonicalize(Tunable(), raw_ps)[1])\nx_nominal = getter(prob)\ndiffcache = DiffCache(tunable_vector_prototype, Val(length(x_nominal)))\n\n#Package context containing all required structural parameters\np_tuple = (prob, grid_steps, nom_features, setter, diffcache, target_observables)\n\n#Wrap into global safe closure for direct evaluation\np_nominal = getter(prob)\nf_wrapped = θ -> loss_function(θ, p_tuple)\n\n#Pre-allocate ForwardDiff configuration for non-allocating gradient evaluations\ncfg = ForwardDiff.GradientConfig(f_wrapped, p_nominal, ForwardDiff.Chunk(p_nominal))\n\n#Non-allocating, in-place gradient function required by MinimallyDisruptiveCurves\ngrad_wrapped! = function (g, θ)\n    return ForwardDiff.gradient!(g, f_wrapped, θ, cfg)\nend","title":"Build the MDC context"},{"category":"section","location":"examples/04_lotka_volterra_with_optim/#MDC-Generation-Pipeline","page":"MTK Lotka-Volterra","text":"println(\"--- Setting up MTK Lotka-Volterra MDC System ---\")\n\n#Compute local curvature Hessian matrix manually\nhess0 = ForwardDiff.hessian(f_wrapped, p_nominal)\neigen_decomposition = eigen(Symmetric(hess0))\n\n#Extract selected eigenvector corresponding to initial curve direction\ninit_dir = eigen_decomposition.vectors[:, EXPLORATION_DIR]\n\n#Extract clean names\nparam_names = params_to_optimize .|> Symbol\n\n#Pass BOTH the objective and its in-place gradient function into CostFunction\nbase_cost = CostFunction(f_wrapped, grad_wrapped!)\n\npipeline = TransformChain()\nfinal_cost = TransformedCost(base_cost, pipeline)\n\nx_nominal_transformed = MinimallyDisruptiveCurves.inverse(pipeline, p_nominal)\nhess0_trans = ForwardDiff.hessian(θ -> final_cost(θ), x_nominal_transformed)\neigen_trans = eigen(Symmetric(hess0_trans))\ninit_dir_trans = eigen_trans.vectors[:, EXPLORATION_DIR]\n\n#Build MDC system\nmdc_sys = MDCProblem(\n    final_cost,\n    x_nominal_transformed,\n    init_dir_trans,\n    10.0;\n    names = param_names\n)\n\nstabiliser = mdc_momentum_readjustment(mdc_sys; tol = 1.0e-3)\nmy_pipeline = CallbackSet(stabiliser)\n\nprintln(\"Launching MDC...\")\n@time mdc_curves = MDCSolve(mdc_sys, span = MDCSpan(-3.0, 10.0); callback = my_pipeline)","title":"MDC Generation Pipeline"},{"category":"section","location":"examples/04_lotka_volterra_with_optim/#Animation-Pipeline-Integration","page":"MTK Lotka-Volterra","text":"println(\"\\nPreparing continuous manifold animation...\")\n\n#Define the live sandbox rendering function\nfunction lotka_volterra_sandbox_painter(θ_physical)\n    plot_t_grid = range(TSPAN_PHYSICAL[1], TSPAN_PHYSICAL[2], length = 200)\n\n    #1. Cleanly update nominal parameters\n    ps_nom_ctx = copy(raw_ps)\n    setter(ps_nom_ctx, p_nominal)\n    prob_nom = remake(prob; p = ps_nom_ctx)\n    sol_nominal = solve(prob_nom, Tsit5(); saveat = plot_t_grid)\n\n    #2. Cleanly update perturbed physical parameters\n    ps_pert_ctx = copy(raw_ps)\n    setter(ps_pert_ctx, θ_physical)\n    prob_pert = remake(prob; p = ps_pert_ctx)\n    sol_perturbed = solve(prob_pert, Tsit5(); saveat = plot_t_grid)\n\n    #3. Extract states\n    states_nom = sol_nominal(plot_t_grid, idxs = target_observables)\n    states_pert = sol_perturbed(plot_t_grid, idxs = target_observables)\n\n    prey_nominal = states_nom[1, :]\n    pred_nominal = states_nom[2, :]\n    prey_perturbed = states_pert[1, :]\n    pred_perturbed = states_pert[2, :]\n\n    mean_prey_nom = mean(prey_nominal)\n    mean_prey_pert = mean(prey_perturbed)\n    max_pred_nom = maximum(pred_nominal)\n    max_pred_pert = maximum(pred_perturbed)\n\n    Plots.plot!(\n        subplot = 1,\n        plot_t_grid, [prey_nominal pred_nominal],\n        linealpha = 0.2, linestyle = :dash,\n        color = [:blue :red], label = false\n    )\n\n    Plots.plot!(\n        subplot = 1,\n        plot_t_grid, [prey_perturbed pred_perturbed],\n        linewidth = 2,\n        color = [:blue :red], label = [\"Prey (x)\" \"Predator (y)\"],\n        legend = :topright\n    )\n\n    Plots.hline!([mean_prey_nom], subplot = 1, linestyle = :dot, linealpha = 0.4, color = :blue, label = false)\n    Plots.hline!([max_pred_nom], subplot = 1, linestyle = :dot, linealpha = 0.4, color = :red, label = false)\n\n    Plots.hline!([mean_prey_pert], subplot = 1, linestyle = :dashdot, linewidth = 1.2, color = :darkblue, label = \"Mean Prey\")\n    Plots.hline!([max_pred_pert], subplot = 1, linestyle = :dashdot, linewidth = 1.2, color = :darkred, label = \"Max Predator\")\n\n    return Plots.plot!(\n        subplot = 1,\n        xlabel = \"Time\", ylabel = \"Population\",\n        xlims = TSPAN_PHYSICAL,\n        ylims = (0.0, 6.0)\n    )\nend\n\n#Invoke updated linear animation tracking utility function\nlv_animation = MinimallyDisruptiveCurves.animate_mdc(\n    mdc_curves,\n    lotka_volterra_sandbox_painter;\n    fps = 20,\n    density = 150,\n    raw = true\n)\n\noutput_path = joinpath(pwd(), \"lotka_volterra_mtk_mdc.gif\")\nprintln(\"Rendering frames and saving video to: $output_path\")\nPlots.gif(lv_animation, output_path);\nnothing #hide\n\n(Image: MTK Lotka Volterra MDC Sweep)\n\n\n\nThis page was generated using Literate.jl.","title":"Animation Pipeline Integration"},{"category":"section","location":"examples/05_nfkb/#Large-Scale-Demonstration:-NFKB-Parameter-Identification","page":"NFKB model","text":"This script consolidates the complete workflow of using MinimallyDisruptiveCurves.jl on a complex biological model. We build an NFKB signaling pathway using ModelingToolkit.jl, define a simulation-based cost function, compute sparse sensitivities, and trace minimally disruptive curves through the high-dimensional parameter space. We also sparsify the parameters involved in our curves, which we haven't done previously. Curves involving fewer parameters are easier to interpret. The model is taken from: Lipniacki, Tomasz, et al. \"Mathematical model of NF-κB regulatory module.\" Journal of theoretical biology 228.2 (2004): 195-215.\n\nusing ModelingToolkit\nusing ModelingToolkitStandardLibrary.Blocks\nusing OrdinaryDiffEq\nusing SciMLStructures: Tunable, canonicalize, replace\nusing PreallocationTools\nusing ForwardDiff\nusing MinimallyDisruptiveCurves\nusing ModelingToolkit: SymbolicT\nusing Plots\nusing SymbolicIndexingInterface\nusing SymbolicIndexingInterface: parameter_values\nusing SciMLBase\nusing LinearAlgebra","title":"Large-Scale Demonstration: NFKB Parameter Identification"},{"category":"section","location":"examples/05_nfkb/#1.-Model-Definition","page":"NFKB model","text":"We define the NFKB pathway components and connect them to a stimulatory input. The model tracks various cytoplasmic and nuclear species, exposing key observables.\n\nconst t = ModelingToolkit.t_nounits\nconst D = ModelingToolkit.D_nounits\n\n@component function NFKBWithPort(; name)\n    @variables begin\n        IKKN(t) = 0.0\n        IKKa(t) = 0.0\n        IKKi(t) = 0.0\n        IKKaIkBa(t) = 0.0\n        IKKaIkBaNfKb(t) = 0.0\n        NFkB(t) = 0.0\n        NFkBn(t) = 0.0\n        A20(t) = 0.0\n        A20t(t) = 0.0\n        IkBa(t) = 0.0\n        IkBan(t) = 0.0\n        IkBat(t) = 0.0\n        IkBaNfKb(t) = 0.06\n        IkBaNfKbn(t) = 0.0\n        Cgent(t) = 0.0\n        NFkBn_obs(t)\n        IkBa_cyto_obs(t)\n        A20t_obs(t)\n        IKKtot_obs(t)\n        IKKa_obs(t)\n        IkBat_obs(t)\n    end\n\n    vars = SymbolicT[]\n    push!(vars, IKKN); push!(vars, IKKa); push!(vars, IKKi); push!(vars, IKKaIkBa)\n    push!(vars, IKKaIkBaNfKb); push!(vars, NFkB); push!(vars, NFkBn); push!(vars, A20)\n    push!(vars, A20t); push!(vars, IkBa); push!(vars, IkBan); push!(vars, IkBat)\n    push!(vars, IkBaNfKb); push!(vars, IkBaNfKbn); push!(vars, Cgent)\n    push!(vars, NFkBn_obs); push!(vars, IkBa_cyto_obs); push!(vars, A20t_obs)\n    push!(vars, IKKtot_obs); push!(vars, IKKa_obs); push!(vars, IkBat_obs)\n\n    @parameters begin\n        kprod = 2.5e-5; kdeg = 0.000125; k1 = 0.0025; k2 = 0.1; k3 = 0.0015\n        a1 = 0.5; a2 = 0.2; a3 = 1.0; t1 = 0.1; t2 = 0.1; c6a = 2.0e-5\n        i1 = 0.0025; kv = 5.0; c1 = 5.0e-7; c3 = 0.0004; c4 = 0.5\n        c5 = 0.0003; c4a = 0.5; c5a = 0.0001; i1a = 0.001; e1a = 0.0005\n        c1a = 5.0e-7; c3a = 0.0004; e2a = 0.01\n\n        c2 = 0.0, [tunable = false]\n        c2a = 0.0, [tunable = false]\n        c1c = 5.0e-7, [tunable = false]\n        c2c = 0.0, [tunable = false]\n        c3c = 0.0004, [tunable = false]\n    end\n\n    params = SymbolicT[]\n    push!(params, kprod); push!(params, kdeg); push!(params, k1); push!(params, k2); push!(params, k3)\n    push!(params, a1); push!(params, a2); push!(params, a3); push!(params, t1); push!(params, t2); push!(params, c6a)\n    push!(params, i1); push!(params, kv); push!(params, c1); push!(params, c3); push!(params, c4)\n    push!(params, c5); push!(params, c4a); push!(params, c5a); push!(params, i1a); push!(params, e1a)\n    push!(params, c1a); push!(params, c3a); push!(params, e2a); push!(params, c2); push!(params, c2a)\n    push!(params, c1c); push!(params, c2c); push!(params, c3c)\n\n    remf_input = RealInput(; name = :remf_input)\n\n    eqs = Equation[]\n    push!(eqs, D(IKKN) ~ kprod - kdeg * IKKN - k1 * IKKN * remf_input.u)\n    push!(eqs, D(IKKa) ~ -k3 * IKKa - kdeg * IKKa - a2 * IKKa * IkBa + t1 * IKKaIkBa - a3 * IKKa * IkBaNfKb + t2 * IKKaIkBaNfKb + (k1 * IKKN - k2 * IKKa * A20) * remf_input.u)\n    push!(eqs, D(IKKi) ~ k3 * IKKa - kdeg * IKKi + k2 * IKKa * A20 * remf_input.u)\n    push!(eqs, D(IKKaIkBa) ~ a2 * IKKa * IkBa - t1 * IKKaIkBa)\n    push!(eqs, D(IKKaIkBaNfKb) ~ a3 * IKKa * IkBaNfKb - t2 * IKKaIkBaNfKb)\n    push!(eqs, D(NFkB) ~ c6a * IkBaNfKb - a1 * NFkB * IkBa + t2 * IKKaIkBaNfKb - i1 * NFkB)\n    push!(eqs, D(NFkBn) ~ i1 * kv * NFkB - a1 * IkBan * NFkBn)\n    push!(eqs, D(A20) ~ c4 * A20t - c5 * A20)\n    push!(eqs, D(A20t) ~ c2 + c1 * NFkBn - c3 * A20t)\n    push!(eqs, D(IkBa) ~ -a2 * IKKa * IkBa - a1 * IkBa * NFkB + c4a * IkBat - c5a * IkBa - i1a * IkBa + e1a * IkBan)\n    push!(eqs, D(IkBan) ~ -a1 * IkBan * NFkBn + i1a * kv * IkBa - e1a * kv * IkBan)\n    push!(eqs, D(IkBat) ~ c2a + c1a * NFkBn - c3a * IkBat)\n    push!(eqs, D(IkBaNfKb) ~ a1 * IkBa * NFkB - c6a * IkBaNfKb - a3 * IKKa * IkBaNfKb + e2a * IkBaNfKbn)\n    push!(eqs, D(IkBaNfKbn) ~ a1 * IkBan * NFkBn - e2a * kv * IkBaNfKbn)\n    push!(eqs, D(Cgent) ~ c2c + c1c * NFkBn - c3c * Cgent)\n    push!(eqs, NFkBn_obs ~ NFkBn)\n    push!(eqs, IkBa_cyto_obs ~ IkBa + IkBaNfKb)\n    push!(eqs, A20t_obs ~ A20t)\n    push!(eqs, IKKtot_obs ~ IKKN + IKKa + IKKi)\n    push!(eqs, IKKa_obs ~ IKKa)\n    push!(eqs, IkBat_obs ~ IkBat)\n\n    sub_systems = System[]\n    push!(sub_systems, remf_input)\n\n    initial_conditions = Dict{SymbolicT, SymbolicT}()\n    guesses = Dict{SymbolicT, SymbolicT}()\n\n    return ODESystem(\n        eqs, t, vars, params;\n        name = name,\n        systems = sub_systems,\n        initial_conditions = initial_conditions,\n        guesses = guesses\n    )\nend\n\n@component function NetworkSystem(; name)\n    pathway = NFKBWithPort(; name = :pathway)\n\n    t_switch = 3600.0\n    steepness = 0.1\n    height = 1.0\n\n    eqs = Equation[]\n    push!(eqs, pathway.remf_input.u ~ height / (1.0 + exp(-steepness * (t - t_switch))))\n\n    sub_systems = System[]\n    push!(sub_systems, pathway)\n\n    return ODESystem(\n        eqs, t, SymbolicT[], SymbolicT[];\n        name = name,\n        systems = sub_systems,\n        initial_conditions = Dict{SymbolicT, SymbolicT}(),\n        guesses = Dict{SymbolicT, SymbolicT}()\n    )\nend\n\nbuild_nfkb() = NetworkSystem(; name = :env) |> structural_simplify","title":"1. Model Definition"},{"category":"section","location":"examples/05_nfkb/#2.-Setup-MTK-Network-and-Base-ODE-Problem","page":"NFKB model","text":"We instantiate the system, define the time span, and generate the baseline experimental data that will serve as the target for our cost function.\n\nsys = build_nfkb()\ntspan = (0.0, 3600.0)\nprob = ODEProblem(sys, [], tspan)\n\ntarget_observables = [\n    sys.pathway.NFkBn_obs,\n    sys.pathway.IkBa_cyto_obs,\n    sys.pathway.A20t_obs,\n    sys.pathway.IKKtot_obs,\n    sys.pathway.IKKa_obs,\n    sys.pathway.IkBat_obs,\n]","title":"2. Setup MTK Network & Base ODE Problem"},{"category":"section","location":"examples/05_nfkb/#3.-Dynamic-Parameter-Identification","page":"NFKB model","text":"We identify the tunable parameters from the system and generate the nominal truth data.\n\nparams_to_optimize = tunable_parameters(sys) ∩ parameters(sys)\n\nprintln(\"Natively optimizing $(length(params_to_optimize)) tunable parameters.\")\n\ntimesteps = 0.0:10.0:3600.0\nsol_nominal = solve(prob, Tsit5(); saveat = timesteps)\ntruth_data = Array(sol_nominal(timesteps, idxs = target_observables))","title":"3. Dynamic Parameter Identification"},{"category":"section","location":"examples/05_nfkb/#4.-High-Performance-Loss-Function","page":"NFKB model","text":"We define an allocation-friendly loss function that uses PreallocationTools and SciMLStructures to efficiently swap out parameter values and propagate Dual numbers through the ODE solver for automatic differentiation.\n\nfunction loss_function(x, p_tuple)\n    odeprob, ts, truth, setter, diffcache, obs_symbols = p_tuple\n\n    ps = parameter_values(odeprob)\n    buffer = get_tmp(diffcache, x)\n\n    copyto!(buffer, canonicalize(Tunable(), ps)[1])\n    ps_updated = replace(Tunable(), ps, buffer)\n    setter(ps_updated, x)\n\n    newprob = remake(odeprob; p = ps_updated)\n    sol = solve(newprob, Tsit5(); saveat = ts)\n\n    if sol.retcode != SciMLBase.ReturnCode.Success\n        return eltype(x)(Inf)\n    end\n\n    current_data = sol(ts, idxs = obs_symbols)\n    return sum(abs2, truth .- current_data) / length(truth)\nend\n\nsetter = setp(prob, params_to_optimize)\ngetter = getp(prob, params_to_optimize)\n\nraw_ps = parameter_values(prob)\ntunable_vector_prototype = copy(canonicalize(Tunable(), raw_ps)[1])\ndiffcache = DiffCache(tunable_vector_prototype)\n\np_tuple = (prob, timesteps, truth_data, setter, diffcache, target_observables)","title":"4. High-Performance Loss Function"},{"category":"section","location":"examples/05_nfkb/#5.-Evaluation-and-Gradient-Verification","page":"NFKB model","text":"We set up the ForwardDiff configurations, wrap the cost and gradient into the CostFunction structure, and apply a LogAbsTransform to explore parameter sensitivities in relative (log) space.\n\nprintln(\"\\n--- Running Scaled Loss Function Evaluation ---\")\n\nx_nominal = getter(prob)\nloss_at_nominal = loss_function(x_nominal, p_tuple)\n\nf_wrapped = θ -> loss_function(θ, p_tuple)\n\nx_nominal = getter(prob)\ncfg = ForwardDiff.GradientConfig(f_wrapped, x_nominal, ForwardDiff.Chunk(x_nominal))\n\ngrad_wrapped! = function (g, θ)\n    return ForwardDiff.gradient!(g, f_wrapped, θ, cfg)\nend\n\nbase_cost = CostFunction(f_wrapped, grad_wrapped!)\npipeline = TransformChain(LogAbsTransform())\nfinal_cost = TransformedCost(base_cost, pipeline)\nx_nominal_transformed = MinimallyDisruptiveCurves.inverse(pipeline, x_nominal)","title":"5. Evaluation and Gradient Verification"},{"category":"section","location":"examples/05_nfkb/#6.-Sparse-Eigenbasis-and-MDC-Execution","page":"NFKB model","text":"We compute the Hessian at the nominal point to determine the initially insensitive directions. Rather than initialising along the raw eigenvectors (which are pretty dense, involving lots of nonzero parameter directions), we sparsity The λ parameter is the degree of sparsification. Higher λ means sparser initial directions\n\nhess0 = ForwardDiff.hessian(θ -> final_cost(θ), x_nominal_transformed)\nvs, vals = sparse_eigenbasis(hess0, 6; λ = 0.0001)\n\nmdc_curves = Dict{Int, Any}()\n\nfor i in 1:5\n    println(\"--- Running MDC for index i = $i ---\")\n\n    _mdc_sys = MDCProblem(\n        final_cost,\n        x_nominal_transformed,\n        vs[i],\n        1.0;\n        names = params_to_optimize .|> Symbol\n    )\n\n    stabiliser = mdc_momentum_readjustment(_mdc_sys; tol = 1.0e-3)\n    my_pipeline = CallbackSet(stabiliser)\n\n    @time curves_i = MDCSolve(_mdc_sys, span = MDCSpan(-10.0, 10.0); callback = my_pipeline)\n\n    mdc_curves[i] = curves_i\nend","title":"6. Sparse Eigenbasis and MDC Execution"},{"category":"section","location":"examples/05_nfkb/#7.-Visualizing-the-MDC-Trajectories","page":"NFKB model","text":"For each curve, we create a figure with  two subplots: the parameter trajectories on top, and the cost trajectory on the bottom. We use the built-in cost_trajectory accessor to evaluate the cost along a uniform grid. We only show the 5 biggest moving parameters to avoid crowding\n\nt_grid = range(-10.0, 10.0, length = 200)\n\n\nfunction build_plot(i)\n    p_params = plot(mdc_curves[i], max_lines = 5)\n    cost_vals = cost_trajectory(mdc_curves[i], t_grid)\n    p_cost = plot(t_grid, cost_vals, label = \"Cost\", xlabel = \"Arc Length\", ylabel = \"Cost\", color = :black)\n    return plot(p_params, p_cost, layout = (2, 1), size = (800, 600))\nend;\nnothing #hide","title":"7. Visualizing the MDC Trajectories"},{"category":"section","location":"examples/05_nfkb/#Trajectory-1","page":"NFKB model","text":"build_plot(1)","title":"Trajectory 1"},{"category":"section","location":"examples/05_nfkb/#Trajectory-2","page":"NFKB model","text":"build_plot(2)","title":"Trajectory 2"},{"category":"section","location":"examples/05_nfkb/#Trajectory-3","page":"NFKB model","text":"build_plot(3)","title":"Trajectory 3"},{"category":"section","location":"examples/05_nfkb/#Trajectory-4","page":"NFKB model","text":"build_plot(4)","title":"Trajectory 4"},{"category":"section","location":"examples/05_nfkb/#Trajectory-5","page":"NFKB model","text":"build_plot(5)\n\n\n\nThis page was generated using Literate.jl.","title":"Trajectory 5"},{"category":"section","location":"examples/02_transforming_costs/","page":"Mass-Spring with Transforms","text":"ENV[\"GKSwstype\"] = \"100\";\nnothing #hide","title":"Mass-Spring with Transforms"},{"category":"section","location":"examples/02_transforming_costs/#Mass-Spring-System-with-Transforms","page":"Mass-Spring with Transforms","text":"This example builds directly on the basic mass-spring system. Here, we introduce TransformChains to constrain and re-parameterize our search space.\n\nSpecifically, we will: Fix the mass parameter m so it cannot change, using FixedParamsTransform. Explore the damping c and stiffness k parameters in log-space using LogAbsTransform, Meaning the MDC will trace through relative changes rather than absolute changes.\n\n#note\n#As in the previous example, we use a lucky guess for the initial direction.\n\nusing LinearAlgebra, OrdinaryDiffEq, MinimallyDisruptiveCurves, Plots\nusing ForwardDiff","title":"Mass-Spring System with Transforms"},{"category":"section","location":"examples/02_transforming_costs/#Simulator","page":"Mass-Spring with Transforms","text":"Standard 2D mass-spring-damper vector field: dotx = v, dotv = -(cm)v - (km)x.\n\nfunction mass_spring_dynamics!(du, u, p, t)\n    m, c, k = p\n    position, velocity = u[1], u[2]\n\n    du[1] = velocity\n    du[2] = -(c / m) * velocity - (k / m) * position\n    return nothing\nend","title":"Simulator"},{"category":"section","location":"examples/02_transforming_costs/#Dynamic-Cost-Function-Factory","page":"Mass-Spring with Transforms","text":"We reuse the MSE cost function factory. It pre-computes a reference trajectory using θ_nominal and evaluates the MSE deviation for any test parameter vector θ.\n\nfunction make_mse_cost_function(θ_nominal; u0 = [1.0, 0.0], tspan = (0.0, 10.0), dt = 0.1)\n    #1. Generate the immutable reference trajectory data\n    prob_nominal = ODEProblem(mass_spring_dynamics!, u0, tspan, θ_nominal)\n    sol_nominal = solve(prob_nominal, Tsit5(), saveat = dt)\n\n    target_times = sol_nominal.t\n    target_positions = [sol[1] for sol in sol_nominal.u]\n\n    #2. Define the objective function closure (f)\n    function f(θ)\n        if any(θ .<= 1.0e-3)\n            return 100.0 + sum(abs2, min.(zero(eltype(θ)), θ))\n        end\n\n        prob = ODEProblem(mass_spring_dynamics!, u0, tspan, θ)\n        sol = solve(prob, Tsit5(), saveat = target_times)\n\n        current_positions = [s[1] for s in sol.u]\n        return sum(abs2, current_positions .- target_positions) / length(target_times)\n    end\n\n    #3. Define the exact Automatic Differentiation gradient closure (grad!)\n    function grad!(g, θ)\n        ForwardDiff.gradient!(g, f, θ)\n        return g\n    end\n\n    return CostFunction(f, grad!)\nend","title":"Dynamic Cost Function Factory"},{"category":"section","location":"examples/02_transforming_costs/#Execution-Pipeline","page":"Mass-Spring with Transforms","text":"Let's define our base physical system nominal profile.\n\nθ_nominal = [1.0, 0.5, 5.0]     #m = 1.0, c = 0.5, k = 5.0\nu0_physical = [1.0, 0.0]\ntspan_physical = (0.0, 10.0)\n\ncore_cost = make_mse_cost_function(θ_nominal, u0 = u0_physical, tspan = tspan_physical)","title":"Execution Pipeline"},{"category":"section","location":"examples/02_transforming_costs/#Wiring-up-the-Transform-Chain","page":"Mass-Spring with Transforms","text":"We want our solver to operate on 2 active parameters: [log(c), log(k)]. The chain applies transforms from left to right in the forward direction.\n\nLogAbsTransform(): maps [log(c), log(k)] to [c, k].\nFixedParamsTransform([2, 3], [1.0], 3): inflates [c, k] to [1.0, c, k] (fixing mass at index 1 to 1.0).\n\nfix_transform = FixedParamsTransform([2, 3], [1.0], 3)\nchain = TransformChain(LogAbsTransform(), fix_transform)\n\ntransformed_cost = TransformedCost(core_cost, chain)","title":"Wiring up the Transform Chain"},{"category":"section","location":"examples/02_transforming_costs/#Instantiating-the-MDC-System","page":"Mass-Spring with Transforms","text":"We must map our 3D nominal physical parameters back into our 2D operational space using the inverse chain.\n\nθ₀ = MinimallyDisruptiveCurves.inverse(chain, θ_nominal)  #Resolves exactly to 2 elements: [log(0.5), log(5.0)]\ndθ₀ = [1.0, 1.0]                #2-element initial direction (lucky guess again!)\nH = 1.0\n\nsys = MDCProblem(\n    transformed_cost,\n    θ₀,\n    dθ₀,\n    H;\n    names = [:mass, :damping, :stiffness]\n)\n\nSetup the stability callback and solve\n\nstabilizer = mdc_momentum_readjustment(sys; tol = 1.0e-3)\nmy_pipeline = CallbackSet(stabilizer)\n\nprintln(\"Launching parallel manifold integration...\")\nmdc_curves = MDCSolve(sys, span = MDCSpan(-5.0, 5.0), callback = my_pipeline; mode = :fast)","title":"Instantiating the MDC System"},{"category":"section","location":"examples/02_transforming_costs/#Verification-and-Analysis","page":"Mass-Spring with Transforms","text":"Let's map the terminal operational state back to physical units to inspect the results.\n\nif mdc_curves.positive_sol !== nothing && mdc_curves.negative_sol !== nothing\n    #Extract the final terminal state coordinates found along the negative integration trace\n    final_operational_state = mdc_curves.negative_sol.u[end]\n    θ_operational_end = final_operational_state[1:length(sys.θ₀)]\n\n    #Map coordinates back to physical units\n    θ_physical_end = forward(chain, θ_operational_end)\n\n    println(\"\\n--- Subspace Constraint Verification ---\")\n    println(\"Initial Physical Configuration: \", round.(θ_nominal, digits = 4))\n    println(\"Terminal Physical Configuration: \", round.(θ_physical_end, digits = 4))\n    println(\"Did Mass stay completely fixed? \", θ_physical_end[1] == θ_nominal[1] ? \"YES (1.0)\" : \"NO\")\n\n    final_cost = core_cost.f(θ_physical_end)\n    println(\"MSE Loss at Path Endpoint: \", round(final_cost, digits = 7))\nelse\n    println(\"Error: MDC integration failed.\")\nend","title":"Verification & Analysis"},{"category":"section","location":"examples/02_transforming_costs/#Animation-Custom-Visualization","page":"Mass-Spring with Transforms","text":"We can reuse our animation function, which operates entirely in physical parameter space.\n\nfunction animate_system_response(θ_current)\n    u0 = [1.0, 0.0]\n    tspan = (0.0, 10.0)\n    dt = 0.1\n\n    prob_nominal = ODEProblem(mass_spring_dynamics!, u0, tspan, θ_nominal)\n    sol_nominal = solve(prob_nominal, Tsit5(), saveat = dt)\n\n    prob_current = ODEProblem(mass_spring_dynamics!, u0, tspan, θ_current)\n    sol_current = solve(prob_current, Tsit5(), saveat = dt)\n\n    pos_nominal = [u[1] for u in sol_nominal.u]\n    pos_current = [u[1] for u in sol_current.u]\n\n    #Plot the ground-truth nominal response as a static dashed black line\n    Plots.plot!(\n        sol_nominal.t, pos_nominal,\n        subplot = 1,\n        line = (:black, :dash),\n        linewidth = 2,\n        label = \"Nominal Target\"\n    )\n\n    #Overlay the explored parameter trajectory response in solid blue\n    return Plots.plot!(\n        sol_current.t, pos_current,\n        subplot = 1,\n        color = :blue,\n        linewidth = 2.5,\n        label = \"MDC Configuration Response\",\n        xlabel = \"Physical Time (s)\",\n        ylabel = \"Position (x)\",\n        ylim = (-1.2, 1.2)\n    )\nend","title":"Animation Custom Visualization"},{"category":"section","location":"examples/02_transforming_costs/#Animation","page":"Mass-Spring with Transforms","text":"We pass raw = true to animate_mdc so it automatically maps the internal coordinates back to physical units before passing them to our painter function.\n\nanim = animate_mdc(mdc_curves, animate_system_response; density = 100, fps = 15, raw = true)\n\nSave the gif and suppress text output with a semicolon\n\ngif(anim, \"mass_spring_transforms_mdc_sweep.gif\", fps = 15);\nnothing #hide\n\n(Image: Mass Spring MDC Sweep with Transforms)\n\n\n\nThis page was generated using Literate.jl.","title":"Animation"},{"category":"section","location":"#MinimallyDisruptiveCurves.jl-Documentation","page":"Home","text":"Welcome to the automated API reference. \n\nFor high-level conceptual user guides and tutorials, please visit the main documentation page:\n\nMain User Guide (Hugo)","title":"MinimallyDisruptiveCurves.jl Documentation"},{"category":"function","location":"#MinimallyDisruptiveCurves.MDCSolve","page":"Home","text":"MDCSolve(sys::MDCProblem; span, mode, dt, callback, parallel, alg=Tsit5()) -> MDCSolution\n\nSolve the Minimally Disruptive Curve (MDC) differential equations for a given system. This function integrates the MDC vector field both forwards and backwards in time from the  initial state, returning an MDCSolution containing the joint trajectory pieces. It internally  constructs a unified initial condition state vector combining parameters theta_0 and  their respective tracking sensitivities lambda_0.\n\nKeyword arguments\n\nspan::MDCSpan: arc-length range to integrate over (default MDCSpan(-10.0, 10.0)).\nalg: any OrdinaryDiffEq.AbstractODEAlgorithm. Defaults to Tsit5(). Pass a stiff solver (e.g. Rodas5()) if your cost function has stiff Jacobians.\nmode: :adaptive (default), :fixed, or :fast.\ndt: step size hint for :fixed and :fast modes.\ncallback: a DiscreteCallback, CallbackSet, or nothing.\nparallel::Bool: solve the forward and backward pieces concurrently via Threads.@spawn.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.MDCSolve"},{"category":"type","location":"#MinimallyDisruptiveCurves.AbstractTransform","page":"Home","text":"Abstract type for transforms that can be chained and applied to a user-supplied cost function inside a TransformChain\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.AbstractTransform"},{"category":"type","location":"#MinimallyDisruptiveCurves.TransformChain","page":"Home","text":"Accepts a tuple of transforms. Chains them together to make a composite transform.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.TransformChain"},{"category":"type","location":"#MinimallyDisruptiveCurves.ScaleTransform","page":"Home","text":"Scales parameters by constants. Correspondingly scales the effort MD curves take to move that parameter (which is the point of this)\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.ScaleTransform"},{"category":"type","location":"#MinimallyDisruptiveCurves.LogAbsTransform","page":"Home","text":"Transforms the parameters by x -> log(abs(x)) (componentwise).\n\nThis means that MDCs trace through relative, rather than absolute, changes in parameters.\nMeans that parameter cannot cross zero (in their raw co-ordinates)\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.LogAbsTransform"},{"category":"type","location":"#MinimallyDisruptiveCurves.FixedParamsTransform","page":"Home","text":"Fixes parameters that the user doesn't wish to change over the MD curve.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.FixedParamsTransform"},{"category":"type","location":"#MinimallyDisruptiveCurves.CostFunction","page":"Home","text":"CostFunction(f, grad!)\nCostFunction(f, grad!, fg)\nCostFunction(fg)\n\nWrap a user-supplied cost function (and its gradient) into a callable struct for use inside a TransformedCost and ultimately an MDCProblem.\n\nConstructors\n\nCostFunction(f, grad!) — separate value and gradient\n\nf(θ)::Number returns the scalar cost at θ.\ngrad!(g, θ) writes the gradient of f at θ into the buffer g and returns g.\n\nThis is the base form. The solver hot loop calls f and grad! separately per RHS evaluation. Fine when the cost and gradient share no expensive forward computation (e.g. analytic costs).\n\nCostFunction(f, grad!, fg) — separate plus combined\n\nfg(g, θ)::Number writes the gradient at θ into g and returns the scalar cost in a single call.\n\nWhen fg is supplied, the solver hot loop uses value_and_gradient! (see Methods below), which calls fg once per RHS evaluation instead of calling f and grad! separately. Use this when the gradient reuses forward work from the cost — most importantly for simulation-based costs where the forward solve is the expensive part and the gradient (via adjoints or forward sensitivities) reuses it.\n\nCostFunction(fg) — convenience constructor\n\nSupply only the combined fg; f and grad! are derived from it. The derived f allocates a temporary gradient buffer on each call, which is acceptable for one-off value queries outside the solver hot loop. For allocation-sensitive standalone value calls, use the 3-arg form with an explicit f.\n\nMethods\n\nvalue(c, θ) returns c.f(θ).\ngradient!(c, g, θ) calls c.grad!(g, θ) and returns g.\nvalue_and_gradient!(c, g, θ) computes both at once:\nif c.fg === nothing, falls back to gradient! then value (two user-side calls);\notherwise calls c.fg(g, θ) once (one user-side call).\n\nTransformedCost uses value_and_gradient! internally on its 3-arg and 4-arg callable forms, so supplying fg halves the user-side call count per RHS evaluation when forward computation can be shared. The 4-arg form ((tc::TransformedCost)(θ, gθ, gz, buffers)) is the allocation-free hot path used by vectorfield(sys).\n\nIn-place gradient contract\n\nBoth grad!(g, θ) and fg(g, θ) must write into the supplied buffer g rather than allocating and returning a fresh array. This matches the solver's preallocation pattern and is what keeps the 4-arg TransformedCost hot path allocation-free. Python-side cost functions supplied via the Python wrapper are adapted to this contract internally by the PyCost adapter; users writing Julia directly must respect it.\n\nExamples\n\nSeparate value and gradient (simple analytic cost):\n\ncenter = [1.0, 2.0, 3.0]\nf(θ) = 0.5 * sum(abs2, θ .- center)\ngrad!(g, θ) = (@. g = θ - center; g)\ncost = CostFunction(f, grad!)\n\nCombined value and gradient (recommended for simulation-based costs where the gradient reuses the forward solve):\n\nfunction fg(g, θ)\n    sol = solve(ODEProblem(dynamics!, u0, tspan, θ), Tsit5())\n    positions = [s[1] for s in sol.u]\n    cost = sum(abs2, positions .- target_positions) / length(positions)\n    # Compute gradient via adjoints or forward sensitivities, reusing `sol`.\n    # ...\n    @. g = computed_gradient\n    return cost\nend\ncost = CostFunction(fg)\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.CostFunction"},{"category":"type","location":"#MinimallyDisruptiveCurves.TransformedCost","page":"Home","text":"TransformedCost(cost, chain)\n\nWraps a CostFunction type. Applies the chain of transforms, each subtypes of AbstractTransform to the cost function, to alter the co-ordinate system the MD curve traces through\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.TransformedCost"},{"category":"type","location":"#MinimallyDisruptiveCurves.MDCProblem","page":"Home","text":"MDCProblem(cost, theta0, dtheta0, momentum, names)\n\nHolds and specifies the information needed to evolve an MD curve. names is an optional vector of symbols holding parameter names.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.MDCProblem"},{"category":"type","location":"#MinimallyDisruptiveCurves.MDCSpan","page":"Home","text":"MDCSpan(lower_bound <= 0, upper_bound >= 0)\n\nSpecifies the length of the MDC curve. negative values mean evolving th curve in the negative direction of the initial direction. If lower_bound < 0 and upper_bound > 0 then the curve evolution happens in two separate solves. \n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.MDCSpan"},{"category":"type","location":"#MinimallyDisruptiveCurves.MDCSolution","page":"Home","text":"Object holding information on evolved curve. (c::MDCurve).spec gives the MDCProblem from which it was generated \n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.MDCSolution"},{"category":"function","location":"#MinimallyDisruptiveCurves.vectorfield","page":"Home","text":"vectorfield(sys::MDCProblem)\n\nFunction factory to generate the vector field for the MDC  \n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.vectorfield"},{"category":"function","location":"#MinimallyDisruptiveCurves.initialise_lambda","page":"Home","text":"Initialises costates based on momentum and initial param direction. Internal use.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.initialise_lambda"},{"category":"function","location":"#MinimallyDisruptiveCurves.mdc_safety_callback","page":"Home","text":"mdc_safety_callback(sys::MDCProblem; tol=1e-4)\n\nReturns a DiscreteCallback that terminates integration if the cost C  approaches or exceeds the total momentum H.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.mdc_safety_callback"},{"category":"function","location":"#MinimallyDisruptiveCurves.mdc_bounds_callback","page":"Home","text":"mdc_bounds_callback(ids, lbs, ubs)\n\nReturns a DiscreteCallback that terminates integration if specified parameter  indices fall outside lower bounds lbs or upper bounds ubs.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.mdc_bounds_callback"},{"category":"function","location":"#MinimallyDisruptiveCurves.mdc_verbose_callbacks","page":"Home","text":"mdc_verbose_callbacks(sys::MDCProblem, timepoints; is_negative=false)\n\nReturns a Tuple of PresetTimeCallbacks for logging the path arc-length and  Hamiltonian energy drift (residual).\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.mdc_verbose_callbacks"},{"category":"function","location":"#MinimallyDisruptiveCurves.mdc_dHdu_residual","page":"Home","text":"mdc_dHdu_residual(sys::MDCProblem, u, t)\n\nComputes the raw L1 numerical drift from dHdu = 0. This operates directly on the raw state vector u.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.mdc_dHdu_residual"},{"category":"function","location":"#MinimallyDisruptiveCurves.mdc_momentum_readjustment","page":"Home","text":"mdc_momentum_readjustment(sys::MDCProblem; tol=1e-2)\n\nCreates a DiscreteCallback that watches the dHdu numerical drift. If it  exceeds tol, the costate (λ) is orthogonally projected back onto the  manifold where the Hamiltonian derivative identity holds.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.mdc_momentum_readjustment"},{"category":"function","location":"#MinimallyDisruptiveCurves.sparse_init_dir","page":"Home","text":"sparse_init_dir(hessian; orthogonal_to=nothing, λ=1.0, start=nothing, trim_level=1e-5, max_iter=2000, tol=1e-6)\n\nConvenience function for generating initial MDC curve directions. Essentially provides sparse eigenvector-correlates for Hessian. Trims tiny nonzero values in the output direction\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.sparse_init_dir"},{"category":"function","location":"#MinimallyDisruptiveCurves.sparse_eigenbasis","page":"Home","text":"sparse_eigenbasis(hessian, num_vectors::Int; λ=1.0, trim_level=1e-5, max_iter=2000, tol=1e-6)\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.sparse_eigenbasis"},{"category":"type","location":"#MinimallyDisruptiveCurves.AbstractCost-index","page":"Home","text":"AbstractCost\n\nAbstract interface for scalar cost functions used by minimally disruptive curves.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.AbstractCost"},{"category":"type","location":"#MinimallyDisruptiveCurves.AbstractTransform-index","page":"Home","text":"Abstract type for transforms that can be chained and applied to a user-supplied cost function inside a TransformChain\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.AbstractTransform"},{"category":"type","location":"#MinimallyDisruptiveCurves.CostFunction-index","page":"Home","text":"CostFunction(f, grad!)\nCostFunction(f, grad!, fg)\nCostFunction(fg)\n\nWrap a user-supplied cost function (and its gradient) into a callable struct for use inside a TransformedCost and ultimately an MDCProblem.\n\nConstructors\n\nCostFunction(f, grad!) — separate value and gradient\n\nf(θ)::Number returns the scalar cost at θ.\ngrad!(g, θ) writes the gradient of f at θ into the buffer g and returns g.\n\nThis is the base form. The solver hot loop calls f and grad! separately per RHS evaluation. Fine when the cost and gradient share no expensive forward computation (e.g. analytic costs).\n\nCostFunction(f, grad!, fg) — separate plus combined\n\nfg(g, θ)::Number writes the gradient at θ into g and returns the scalar cost in a single call.\n\nWhen fg is supplied, the solver hot loop uses value_and_gradient! (see Methods below), which calls fg once per RHS evaluation instead of calling f and grad! separately. Use this when the gradient reuses forward work from the cost — most importantly for simulation-based costs where the forward solve is the expensive part and the gradient (via adjoints or forward sensitivities) reuses it.\n\nCostFunction(fg) — convenience constructor\n\nSupply only the combined fg; f and grad! are derived from it. The derived f allocates a temporary gradient buffer on each call, which is acceptable for one-off value queries outside the solver hot loop. For allocation-sensitive standalone value calls, use the 3-arg form with an explicit f.\n\nMethods\n\nvalue(c, θ) returns c.f(θ).\ngradient!(c, g, θ) calls c.grad!(g, θ) and returns g.\nvalue_and_gradient!(c, g, θ) computes both at once:\nif c.fg === nothing, falls back to gradient! then value (two user-side calls);\notherwise calls c.fg(g, θ) once (one user-side call).\n\nTransformedCost uses value_and_gradient! internally on its 3-arg and 4-arg callable forms, so supplying fg halves the user-side call count per RHS evaluation when forward computation can be shared. The 4-arg form ((tc::TransformedCost)(θ, gθ, gz, buffers)) is the allocation-free hot path used by vectorfield(sys).\n\nIn-place gradient contract\n\nBoth grad!(g, θ) and fg(g, θ) must write into the supplied buffer g rather than allocating and returning a fresh array. This matches the solver's preallocation pattern and is what keeps the 4-arg TransformedCost hot path allocation-free. Python-side cost functions supplied via the Python wrapper are adapted to this contract internally by the PyCost adapter; users writing Julia directly must respect it.\n\nExamples\n\nSeparate value and gradient (simple analytic cost):\n\ncenter = [1.0, 2.0, 3.0]\nf(θ) = 0.5 * sum(abs2, θ .- center)\ngrad!(g, θ) = (@. g = θ - center; g)\ncost = CostFunction(f, grad!)\n\nCombined value and gradient (recommended for simulation-based costs where the gradient reuses the forward solve):\n\nfunction fg(g, θ)\n    sol = solve(ODEProblem(dynamics!, u0, tspan, θ), Tsit5())\n    positions = [s[1] for s in sol.u]\n    cost = sum(abs2, positions .- target_positions) / length(positions)\n    # Compute gradient via adjoints or forward sensitivities, reusing `sol`.\n    # ...\n    @. g = computed_gradient\n    return cost\nend\ncost = CostFunction(fg)\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.CostFunction"},{"category":"type","location":"#MinimallyDisruptiveCurves.FixedParamsTransform-index","page":"Home","text":"Fixes parameters that the user doesn't wish to change over the MD curve.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.FixedParamsTransform"},{"category":"type","location":"#MinimallyDisruptiveCurves.LogAbsTransform-index","page":"Home","text":"Transforms the parameters by x -> log(abs(x)) (componentwise).\n\nThis means that MDCs trace through relative, rather than absolute, changes in parameters.\nMeans that parameter cannot cross zero (in their raw co-ordinates)\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.LogAbsTransform"},{"category":"type","location":"#MinimallyDisruptiveCurves.MDCProblem-index","page":"Home","text":"MDCProblem(cost, theta0, dtheta0, momentum, names)\n\nHolds and specifies the information needed to evolve an MD curve. names is an optional vector of symbols holding parameter names.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.MDCProblem"},{"category":"method","location":"#MinimallyDisruptiveCurves.MDCSolution-Tuple{Real}-index","page":"Home","text":"(curve::MDCSolution)(t::Real)\n\nEnables continuous interpolation across the split-span trajectory.  Routes positive arc-lengths to positive_sol and negative  arc-lengths to negative_sol.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.MDCSolution"},{"category":"type","location":"#MinimallyDisruptiveCurves.MDCSolution-index","page":"Home","text":"Object holding information on evolved curve. (c::MDCurve).spec gives the MDCProblem from which it was generated \n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.MDCSolution"},{"category":"type","location":"#MinimallyDisruptiveCurves.MDCSpan-index","page":"Home","text":"MDCSpan(lower_bound <= 0, upper_bound >= 0)\n\nSpecifies the length of the MDC curve. negative values mean evolving th curve in the negative direction of the initial direction. If lower_bound < 0 and upper_bound > 0 then the curve evolution happens in two separate solves. \n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.MDCSpan"},{"category":"type","location":"#MinimallyDisruptiveCurves.ScaleTransform-index","page":"Home","text":"Scales parameters by constants. Correspondingly scales the effort MD curves take to move that parameter (which is the point of this)\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.ScaleTransform"},{"category":"type","location":"#MinimallyDisruptiveCurves.TransformChain-index","page":"Home","text":"Accepts a tuple of transforms. Chains them together to make a composite transform.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.TransformChain"},{"category":"method","location":"#MinimallyDisruptiveCurves.TransformedCost-Tuple{CostFunction}-index","page":"Home","text":"TransformedCost(core_cost::CostFunction)\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.TransformedCost"},{"category":"type","location":"#MinimallyDisruptiveCurves.TransformedCost-index","page":"Home","text":"TransformedCost(cost, chain)\n\nWraps a CostFunction type. Applies the chain of transforms, each subtypes of AbstractTransform to the cost function, to alter the co-ordinate system the MD curve traces through\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.TransformedCost"},{"category":"method","location":"#MinimallyDisruptiveCurves.MDCSolve-Tuple{MDCProblem}-index","page":"Home","text":"MDCSolve(sys::MDCProblem; span, mode, dt, callback, parallel, alg=Tsit5()) -> MDCSolution\n\nSolve the Minimally Disruptive Curve (MDC) differential equations for a given system. This function integrates the MDC vector field both forwards and backwards in time from the  initial state, returning an MDCSolution containing the joint trajectory pieces. It internally  constructs a unified initial condition state vector combining parameters theta_0 and  their respective tracking sensitivities lambda_0.\n\nKeyword arguments\n\nspan::MDCSpan: arc-length range to integrate over (default MDCSpan(-10.0, 10.0)).\nalg: any OrdinaryDiffEq.AbstractODEAlgorithm. Defaults to Tsit5(). Pass a stiff solver (e.g. Rodas5()) if your cost function has stiff Jacobians.\nmode: :adaptive (default), :fixed, or :fast.\ndt: step size hint for :fixed and :fast modes.\ncallback: a DiscreteCallback, CallbackSet, or nothing.\nparallel::Bool: solve the forward and backward pieces concurrently via Threads.@spawn.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.MDCSolve"},{"category":"function","location":"#MinimallyDisruptiveCurves.animate_mdc-index","page":"Home","text":"animate_mdc(args...; kwargs...)\n\nPlotting extension hook for animations of minimally disruptive curves.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.animate_mdc"},{"category":"method","location":"#MinimallyDisruptiveCurves.cost_trajectory-Tuple{MinimallyDisruptiveCurves.MDCSolution, AbstractVector}-index","page":"Home","text":"cost_trajectory(curve[, ts])\n\nEvaluate the curve's cost along the supplied time grid, or along saved solution times.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.cost_trajectory"},{"category":"method","location":"#MinimallyDisruptiveCurves.forward!-Tuple{Any, ScaleTransform, Any}-index","page":"Home","text":"forward!(out, transform, x)\nforward!(chain, buffers, x)\n\nIn-place form of forward, using caller-provided output storage.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.forward!"},{"category":"method","location":"#MinimallyDisruptiveCurves.forward-Tuple{TransformChain, Any}-index","page":"Home","text":"forward(transform, x)\n\nMap parameters from transformed coordinates to physical coordinates.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.forward"},{"category":"method","location":"#MinimallyDisruptiveCurves.generate_fwd_caches-Tuple{TransformChain, Any}-index","page":"Home","text":"generate_fwd_caches(chain, θ₀)\n\nAllocate reusable buffers for in-place forward transforms through chain.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.generate_fwd_caches"},{"category":"method","location":"#MinimallyDisruptiveCurves.gradient!-Tuple{CostFunction, Any, Any}-index","page":"Home","text":"gradient!(c, g, θ)\n\nWrite the gradient of cost c at parameters θ into g and return g.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.gradient!"},{"category":"method","location":"#MinimallyDisruptiveCurves.initialise_lambda-Tuple{MDCProblem, MinimallyDisruptiveCurves.MDCWorkspace}-index","page":"Home","text":"Initialises costates based on momentum and initial param direction. Internal use.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.initialise_lambda"},{"category":"method","location":"#MinimallyDisruptiveCurves.inverse-Tuple{TransformChain, Any}-index","page":"Home","text":"inverse(transform, y)\n\nMap parameters from physical coordinates back to transformed coordinates.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.inverse"},{"category":"method","location":"#MinimallyDisruptiveCurves.mdc_bounds_callback-Tuple{Vector{<:Integer}, Vector{<:Number}, Vector{<:Number}}-index","page":"Home","text":"mdc_bounds_callback(ids, lbs, ubs)\n\nReturns a DiscreteCallback that terminates integration if specified parameter  indices fall outside lower bounds lbs or upper bounds ubs.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.mdc_bounds_callback"},{"category":"method","location":"#MinimallyDisruptiveCurves.mdc_dHdu_residual-Tuple{MDCProblem, Any, Any}-index","page":"Home","text":"mdc_dHdu_residual(sys::MDCProblem, u, t)\n\nComputes the raw L1 numerical drift from dHdu = 0. This operates directly on the raw state vector u.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.mdc_dHdu_residual"},{"category":"method","location":"#MinimallyDisruptiveCurves.mdc_momentum_readjustment-Tuple{MDCProblem}-index","page":"Home","text":"mdc_momentum_readjustment(sys::MDCProblem; tol=1e-2)\n\nCreates a DiscreteCallback that watches the dHdu numerical drift. If it  exceeds tol, the costate (λ) is orthogonally projected back onto the  manifold where the Hamiltonian derivative identity holds.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.mdc_momentum_readjustment"},{"category":"method","location":"#MinimallyDisruptiveCurves.mdc_safety_callback-Tuple{MDCProblem}-index","page":"Home","text":"mdc_safety_callback(sys::MDCProblem; tol=1e-4)\n\nReturns a DiscreteCallback that terminates integration if the cost C  approaches or exceeds the total momentum H.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.mdc_safety_callback"},{"category":"method","location":"#MinimallyDisruptiveCurves.mdc_verbose_callbacks-Tuple{MDCProblem, Any}-index","page":"Home","text":"mdc_verbose_callbacks(sys::MDCProblem, timepoints; is_negative=false)\n\nReturns a Tuple of PresetTimeCallbacks for logging the path arc-length and  Hamiltonian energy drift (residual).\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.mdc_verbose_callbacks"},{"category":"method","location":"#MinimallyDisruptiveCurves.pullback!-Tuple{TransformChain, Any, Any}-index","page":"Home","text":"pullback!(transform, g_in, g_out, x, y)\n\nPull a gradient in physical coordinates back through transform.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.pullback!"},{"category":"method","location":"#MinimallyDisruptiveCurves.sparse_eigenbasis-Tuple{Any, Int64}-index","page":"Home","text":"sparse_eigenbasis(hessian, num_vectors::Int; λ=1.0, trim_level=1e-5, max_iter=2000, tol=1e-6)\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.sparse_eigenbasis"},{"category":"method","location":"#MinimallyDisruptiveCurves.sparse_init_dir-Tuple{Any}-index","page":"Home","text":"sparse_init_dir(hessian; orthogonal_to=nothing, λ=1.0, start=nothing, trim_level=1e-5, max_iter=2000, tol=1e-6)\n\nConvenience function for generating initial MDC curve directions. Essentially provides sparse eigenvector-correlates for Hessian. Trims tiny nonzero values in the output direction\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.sparse_init_dir"},{"category":"method","location":"#MinimallyDisruptiveCurves.value_and_gradient!-Tuple{AbstractCost, Any, Any}-index","page":"Home","text":"value_and_gradient!(c, g, θ)\n\nWrite the gradient of cost c at θ into g and return the scalar cost value.\n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.value_and_gradient!"},{"category":"method","location":"#MinimallyDisruptiveCurves.vectorfield-Tuple{MDCProblem}-index","page":"Home","text":"vectorfield(sys::MDCProblem)\n\nFunction factory to generate the vector field for the MDC  \n\n\n\n\n\n","title":"MinimallyDisruptiveCurves.vectorfield"},{"category":"section","location":"examples/01_basic_mass_spring/","page":"Basic Mass-Spring","text":"ENV[\"GKSwstype\"] = \"100\";\nnothing #hide","title":"Basic Mass-Spring"},{"category":"section","location":"examples/01_basic_mass_spring/#Basic-Mass-Spring-System","page":"Basic Mass-Spring","text":"This example shows how Minimally Disruptive Curves (MDC) finds a structural unidentifiability in the basic damped harmonic oscillator model (where m is mass, c is damping, and k is the spring constant). We will see that the trajectory doesn't vary where the ratios c/m and k/m remain constant. This is obvious algebraically, as the equations are dotv = -(cm)v - (km)x.\n\nnote: Note\nThis script does not explore how to initialise a good starting MDC direction. We make a lucky guess here. That's the topic of the next Lotka-Volterra example (and the NFKB example)\n\nusing LinearAlgebra, OrdinaryDiffEq, MinimallyDisruptiveCurves, Plots\nusing ForwardDiff","title":"Basic Mass-Spring System"},{"category":"section","location":"examples/01_basic_mass_spring/#Simulator","page":"Basic Mass-Spring","text":"We define the standard 2D mass-spring-damper vector field: dotx = v, dotv = -(cm)v - (km)x.\n\nfunction mass_spring_dynamics!(du, u, p, t)\n    m, c, k = p\n    position, velocity = u[1], u[2]\n\n    du[1] = velocity\n    du[2] = -(c / m) * velocity - (k / m) * position\n    return nothing\nend","title":"Simulator"},{"category":"section","location":"examples/01_basic_mass_spring/#Dynamic-Cost-Function-Factory","page":"Basic Mass-Spring","text":"This factory generates a CostFunction instance. It pre-computes a reference trajectory using θ_nominal and evaluates the Mean Squared Error (MSE) deviation for any test parameter vector θ.\n\nfunction make_mse_cost_function(θ_nominal; u0 = [1.0, 0.0], tspan = (0.0, 10.0), dt = 0.1)\n    #1. Generate the immutable reference trajectory data\n    prob_nominal = ODEProblem(mass_spring_dynamics!, u0, tspan, θ_nominal)\n    sol_nominal = solve(prob_nominal, Tsit5(), saveat = dt)\n\n    target_times = sol_nominal.t\n    target_positions = [sol[1] for sol in sol_nominal.u]\n\n    #2. Define the objective function closure (f)\n    function f(θ)\n        if any(θ .<= 1.0e-3)\n            #Ensure the penalty return type matches the input dual/real element type\n            return 100.0 + sum(abs2, min.(zero(eltype(θ)), θ))\n        end\n\n        prob = ODEProblem(mass_spring_dynamics!, u0, tspan, θ)\n        sol = solve(prob, Tsit5(), saveat = target_times)\n\n        current_positions = [s[1] for s in sol.u]\n        return sum(abs2, current_positions .- target_positions) / length(target_times)\n    end\n\n    #3. Define the exact Automatic Differentiation gradient closure (grad!)\n    function grad!(g, θ)\n        ForwardDiff.gradient!(g, f, θ)\n        return g\n    end\n\n    return CostFunction(f, grad!)\nend","title":"Dynamic Cost Function Factory"},{"category":"section","location":"examples/01_basic_mass_spring/#Execution-Pipeline","page":"Basic Mass-Spring","text":"Let's define our base system nominal profile and instantiate the MDC System.\n\nθ_nominal = [1.0, 0.5, 5.0]     #m = 1.0, c = 0.5, k = 5.0\ndθ_nominal = θ_nominal          #Lucky guess for initial direction\nu0_physical = [1.0, 0.0]        #Initial position=1, velocity=0\ntspan_physical = (0.0, 10.0)    #Observe for 10 seconds\n\nBuild the Cost Function mapping parameter variants against the baseline\n\ncore_cost = make_mse_cost_function(θ_nominal, u0 = u0_physical, tspan = tspan_physical)\n\nWire up the Transform Chain (empty in this case, and could directly pass core_cost to the MDCProblem)\n\nchain = TransformChain()\ntransformed_cost = TransformedCost(core_cost, chain)\n\nInstantiate the MDC System\n\nθ₀ = θ_nominal\ndθ₀ = θ_nominal\nH = 1.0                        #Hamiltonian: think of as momentum of the trajectory\n\nsys = MDCProblem(transformed_cost, θ₀, dθ₀, H; names = [:mass, :damping, :stiffness])\n\nSetup the standard stability callback and solve\n\nstabilizer = mdc_momentum_readjustment(sys; tol = 1.0e-3)\nmy_pipeline = CallbackSet(stabilizer)\n\nmdc_curves = MDCSolve(sys, span = MDCSpan(-5.0, 5.0), callback = my_pipeline; mode = :fast)","title":"Execution Pipeline"},{"category":"section","location":"examples/01_basic_mass_spring/#Verification-and-Analysis","page":"Basic Mass-Spring","text":"Let's inspect the parameters discovered at the endpoint of the curve.\n\nfinal_state = mdc_curves.negative_sol.u[end]\nθ_explored = final_state[1:3]\n\nprintln(\"Initial Params (θ₀):          \", round.(θ₀, digits = 4))\nprintln(\"Explored Params (MDC End):   \", round.(θ_explored, digits = 4))\n\nprintln(\"\\nValidating Ratio Preservation:\")\nprintln(\"Initial c/m: \", round(θ₀[2] / θ₀[1], digits = 4), \"  |  Explored c/m: \", round(θ_explored[2] / θ_explored[1], digits = 4))\nprintln(\"Initial k/m: \", round(θ₀[3] / θ₀[1], digits = 4), \"  |  Explored k/m: \", round(θ_explored[3] / θ_explored[1], digits = 4))\n\nCalculate the exact MSE cost at the terminal point of our parameter path\n\nfinal_cost = core_cost.f(θ_explored)\nprintln(\"\\nMSE Cost Relative to Nominal Trajectory: \", round(final_cost, digits = 7))","title":"Verification & Analysis"},{"category":"section","location":"examples/01_basic_mass_spring/#Animation-Custom-Visualization","page":"Basic Mass-Spring","text":"We can define a custom visualization function to pass to animate_mdc, which paints directly onto the plot canvas at each frame.\n\nfunction animate_system_response(θ_current)\n    u0 = [1.0, 0.0]\n    tspan = (0.0, 10.0)\n    dt = 0.1\n\n    prob_nominal = ODEProblem(mass_spring_dynamics!, u0, tspan, θ_nominal)\n    sol_nominal = solve(prob_nominal, Tsit5(), saveat = dt)\n\n    prob_current = ODEProblem(mass_spring_dynamics!, u0, tspan, θ_current)\n    sol_current = solve(prob_current, Tsit5(), saveat = dt)\n\n    pos_nominal = [u[1] for u in sol_nominal.u]\n    pos_current = [u[1] for u in sol_current.u]\n\n    #Plot the ground-truth nominal response as a static dashed black line\n    Plots.plot!(\n        sol_nominal.t, pos_nominal,\n        subplot = 1,\n        line = (:black, :dash),\n        linewidth = 2,\n        label = \"Nominal Target\"\n    )\n\n    #Overlay the explored parameter trajectory response in solid blue\n    return Plots.plot!(\n        sol_current.t, pos_current,\n        subplot = 1,\n        color = :blue,\n        linewidth = 2.5,\n        label = \"MDC Configuration Response\",\n        xlabel = \"Physical Time (s)\",\n        ylabel = \"Position (x)\",\n        ylim = (-1.2, 1.2)\n    )\nend","title":"Animation Custom Visualization"},{"category":"section","location":"examples/01_basic_mass_spring/#Animation","page":"Basic Mass-Spring","text":"We can generate an animation using animate_mdc and save it as a gif:\n\nanim = animate_mdc(mdc_curves, animate_system_response; density = 100, fps = 15, raw = true)\ngif(anim, \"mass_spring_mdc_sweep.gif\", fps = 15);\nnothing #hide\n\n(Image: Mass Spring MDC Sweep)\n\n\n\nThis page was generated using Literate.jl.","title":"Animation"}]
}
